      area,
      areaUnit,
      perimeter,
      modalityUnit,
      radiusUnit,
      radius,
      max,
      min,
      stdDev,
      mean,
      points: [center, end],
      trackingIdentifierTextValue: this.trackingIdentifierTextValue,
      finding,
