import { data, normalizers } from 'dcmjs';

const {
  DicomMessage,
  DicomMetaDictionary
} = data;
const {
  Normalizer
} = normalizers;
function getDatasetsFromImages(images, isMultiframe, options) {
  const datasets = [];
  if (isMultiframe) {
    const image = images[0];
    const arrayBuffer = image.data.byteArray.buffer;
    const dicomData = DicomMessage.readFile(arrayBuffer);
    const dataset = DicomMetaDictionary.naturalizeDataset(dicomData.dict);
    dataset._meta = DicomMetaDictionary.namifyDataset(dicomData.meta);
    datasets.push(dataset);
  } else {
    for (let i = 0; i < images.length; i++) {
      const image = images[i];
      const arrayBuffer = image.data.byteArray.buffer;
      const dicomData = DicomMessage.readFile(arrayBuffer);
      const dataset = DicomMetaDictionary.naturalizeDataset(dicomData.dict);
      dataset._meta = DicomMetaDictionary.namifyDataset(dicomData.meta);
      datasets.push(dataset);
    }
  }
  if (options?.SpecificCharacterSet) {
    datasets.forEach(dataset => dataset.SpecificCharacterSet = options.SpecificCharacterSet);
  }
  return Normalizer.normalizeToDataset(datasets);
}

export { getDatasetsFromImages as default };
